INSERT INTO `nutrition_tips` (`id`, `name`, `content`, `created_at`, `updated_at`) VALUES
(1, 'Cornstarch', 'A 100 g serving of Cornstarch contains 381 calories. Nutritional breakdown: Protein: 0.26 g, Total Fat: 0.1g, Carbohydrates: 91.27 g (including 0.00 g of sugar), and Fiber: 0.9 g.', '2026-04-21 05:48:41', '2026-04-21 05:48:41'),
(2, 'Nuts, pecans', 'A 100 g serving of Nuts, pecans contains 691 calories. Nutritional breakdown: Protein: 9.17 g, Total Fat: 72g, Carbohydrates: 13.86 g (including 3.97 g of sugar), and Fiber: 9.6 g.', '2026-04-21 05:48:41', '2026-04-21 05:48:41'),
(3, 'Eggplant, raw', 'A 100 g serving of Eggplant, raw contains 25 calories. Nutritional breakdown: Protein: 0.98 g, Total Fat: 0.2g, Carbohydrates: 5.88 g (including 3.53 g of sugar), and Fiber: 3.0 g.', '2026-04-21 05:48:41', '2026-04-21 05:48:41'),
